package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.ByteArrayInputStream;
import java.io.File;
import java.io.FileInputStream;
import java.io.InputStream;
import java.io.Reader;
import java.io.StringReader;
import java.net.URL;
import java.nio.charset.Charset;
import java.nio.file.Files;
import java.nio.file.Path;

import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserParseTest {

    private MockedStatic<Assertions> assertionsMockedStatic;
    private MockedStatic<FileInputStream> fileInputStreamMockedStatic;
    private MockedStatic<Files> filesMockedStatic;

    @AfterEach
    void tearDown() {
        if (assertionsMockedStatic != null) {
            assertionsMockedStatic.close();
        }
        if (fileInputStreamMockedStatic != null) {
            fileInputStreamMockedStatic.close();
        }
        if (filesMockedStatic != null) {
            filesMockedStatic.close();
        }
    }

    @Test
    void parse_withFileAndCharsetAndFormat_shouldReturnCSVParser() throws Exception {
        File file = mock(File.class);
        Charset charset = Charset.defaultCharset();
        CSVFormat format = mock(CSVFormat.class);

        assertionsMockedStatic = Mockito.mockStatic(Assertions.class);
        assertionsMockedStatic.when(() -> Assertions.notNull(file, "file")).then(invocation -> null);
        assertionsMockedStatic.when(() -> Assertions.notNull(format, "format")).then(invocation -> null);

        FileInputStream fis = mock(FileInputStream.class);
        fileInputStreamMockedStatic = Mockito.mockStatic(FileInputStream.class);
        fileInputStreamMockedStatic.when(() -> new FileInputStream(file)).thenReturn(fis);

        // Because CSVParser constructor is public CSVParser(Reader, CSVFormat)
        // We spy on CSVParser to verify constructor usage is correct
        // But since constructor is final class, we cannot mock constructor easily
        // Instead, we just call parse and verify no exceptions and non-null

        CSVParser parser = CSVParser.parse(file, charset, format);
        assertNotNull(parser);
    }

    @Test
    void parse_withInputStreamAndCharsetAndFormat_shouldReturnCSVParser() throws Exception {
        InputStream inputStream = new ByteArrayInputStream("a,b\n1,2".getBytes());
        Charset charset = Charset.defaultCharset();
        CSVFormat format = mock(CSVFormat.class);

        assertionsMockedStatic = Mockito.mockStatic(Assertions.class);
        assertionsMockedStatic.when(() -> Assertions.notNull(inputStream, "inputStream")).then(invocation -> null);
        assertionsMockedStatic.when(() -> Assertions.notNull(format, "format")).then(invocation -> null);

        CSVParser parser = CSVParser.parse(inputStream, charset, format);
        assertNotNull(parser);
    }

    @Test
    void parse_withPathAndCharsetAndFormat_shouldReturnCSVParser() throws Exception {
        Path path = mock(Path.class);
        Charset charset = Charset.defaultCharset();
        CSVFormat format = mock(CSVFormat.class);

        assertionsMockedStatic = Mockito.mockStatic(Assertions.class);
        assertionsMockedStatic.when(() -> Assertions.notNull(path, "path")).then(invocation -> null);
        assertionsMockedStatic.when(() -> Assertions.notNull(format, "format")).then(invocation -> null);

        InputStream inputStream = new ByteArrayInputStream("a,b\n1,2".getBytes());
        filesMockedStatic = Mockito.mockStatic(Files.class);
        filesMockedStatic.when(() -> Files.newInputStream(path)).thenReturn(inputStream);

        CSVParser parser = CSVParser.parse(path, charset, format);
        assertNotNull(parser);
    }

    @Test
    void parse_withReaderAndFormat_shouldReturnCSVParser() throws Exception {
        String csv = "a,b\n1,2";
        Reader reader = new StringReader(csv);
        CSVFormat format = mock(CSVFormat.class);

        assertionsMockedStatic = Mockito.mockStatic(Assertions.class);
        assertionsMockedStatic.when(() -> Assertions.notNull(reader, "reader")).then(invocation -> null);
        assertionsMockedStatic.when(() -> Assertions.notNull(format, "format")).then(invocation -> null);

        CSVParser parser = CSVParser.parse(reader, format);
        assertNotNull(parser);
    }

    @Test
    void parse_withStringAndFormat_shouldReturnCSVParser() throws Exception {
        String csv = "a,b\n1,2";
        CSVFormat format = mock(CSVFormat.class);

        assertionsMockedStatic = Mockito.mockStatic(Assertions.class);
        assertionsMockedStatic.when(() -> Assertions.notNull(csv, "string")).then(invocation -> null);
        assertionsMockedStatic.when(() -> Assertions.notNull(format, "format")).then(invocation -> null);

        CSVParser parser = CSVParser.parse(csv, format);
        assertNotNull(parser);
    }

    @Test
    void parse_withUrlAndCharsetAndFormat_shouldReturnCSVParser() throws Exception {
        URL url = mock(URL.class);
        Charset charset = Charset.defaultCharset();
        CSVFormat format = mock(CSVFormat.class);

        InputStream inputStream = new ByteArrayInputStream("a,b\n1,2".getBytes());
        when(url.openStream()).thenReturn(inputStream);

        assertionsMockedStatic = Mockito.mockStatic(Assertions.class);
        assertionsMockedStatic.when(() -> Assertions.notNull(url, "url")).then(invocation -> null);
        assertionsMockedStatic.when(() -> Assertions.notNull(format, "format")).then(invocation -> null);

        CSVParser parser = CSVParser.parse(url, charset, format);
        assertNotNull(parser);
    }
}
